"""Space chatter (C6) — context-driven ambient lines, template-pool driven with fact gating.

Chatter categories are cues (C2) the C3 driver picks and governs. Each declares its eligible
game states, target bus, cooldown, and a curated phrasing pool. The one rule that keeps the
companion honest (the help discipline, applied to audio):

  * fact_bearing cues speak ONLY from their vetted pool — deterministic rotation, never the LLM.
    A fact-bearing line could assert something checkable, so a human wrote every option.
  * flavor cues (fact_bearing=False) may have a line GENERATED by the LLM, but only pure
    atmosphere with nothing checkable; a validator rejects anything with a number or a proper
    noun and the player falls back to the pool. The LLM only ever yields text that is validated
    then routed — it is never in the realtime audio path.

Governed by C3 (cooldowns + the global rate cap) so chatter never over-talks.
"""
from __future__ import annotations

import re
from typing import Callable, Optional

from .buses import COMMS
from .cues import Cue
from .eligibility import DEEP_SPACE, NORMAL_SPACE, POPULATED, SUPERCRUISE, UNPOPULATED

_WORD = re.compile(r"[A-Za-z']+")
_SENTENCE = re.compile(r"[.!?]+")


def _has_proper_noun(text: str) -> bool:
    """Any Title-case / ALL-CAPS token that isn't sentence-initial — i.e. a named entity (a
    system, station, ship, or person). Its presence makes a 'musing' checkable."""
    for sentence in _SENTENCE.split(text or ""):
        toks = _WORD.findall(sentence)
        for i, tok in enumerate(toks):
            if i == 0 or len(tok) < 2:
                continue
            if tok[0].isupper() and (tok.istitle() or tok.isupper()):
                return True
    return False


def is_flavor_safe(text: str) -> bool:
    """A flavor musing must assert NOTHING checkable: no numbers, no proper nouns (named
    systems/stations/ships/people). Pure. Rejected flavor falls back to the curated pool."""
    t = text or ""
    if not t.strip():
        return False
    if any(ch.isdigit() for ch in t):
        return False
    return not _has_proper_noun(t)


def build_chatter_prompt(cue: Cue) -> str:
    """Prompt for a flavor (fact_bearing=False) musing. The validator is the real guard, but the
    prompt still states the rules and offers the pool as tone examples."""
    examples = " / ".join(cue.phrasings[:3]) if cue.phrasings else "(quiet, atmospheric)"
    return (
        "You voice a brief, ambient in-character musing for an Elite Dangerous companion. Say ONE "
        "short line of pure atmosphere — NO specific facts, NO names, NO numbers, nothing "
        "checkable. Just mood.\n"
        f"Tone examples: {examples}\n"
        "Reply with ONLY the line."
    )


class ChatterPlayer:
    """The C3 driver's `play` callback for chatter cues. Chooses a line and routes it to the
    cue's bus, advancing the pool rotation deterministically.

    Injected seams (offline-testable):
      * `speak(text, bus) -> bool` — routes a line to a bus (the app wires this to the mixer),
        returning True only if playback started;
      * `generate(prompt) -> str` — the LLM flavor generator (None => pool-only). Used ONLY for
        fact_bearing=False cues, and only if the result passes `is_flavor_safe`.
    """

    def __init__(
        self,
        speak: Callable[[str, str], bool],
        *,
        generate: Optional[Callable[[str], str]] = None,
        log: Optional[Callable[[str], None]] = None,
    ) -> None:
        self._speak = speak
        self._generate = generate
        self._log = log
        self._rot: dict[str, int] = {}   # per-cue pool rotation pointer

    def line_for(self, cue: Cue) -> tuple[str, str]:
        """(text, source) where source is 'flavor' (validated LLM) or 'pool' (deterministic
        rotation). A fact_bearing cue NEVER reaches the generator."""
        if not cue.fact_bearing and self._generate is not None:
            try:
                candidate = (self._generate(build_chatter_prompt(cue)) or "").strip()
            except Exception:  # noqa: BLE001 — a generator failure degrades to the pool
                candidate = ""
            if candidate and is_flavor_safe(candidate):
                return candidate, "flavor"
        # fact-bearing, no generator, or rejected flavor -> the curated pool, rotated.
        return cue.phrasing_at(self._rot.get(cue.name, 0)), "pool"

    def __call__(self, cue: Cue) -> bool:
        text, source = self.line_for(cue)
        if not text.strip():
            return False
        started = bool(self._speak(text, cue.bus))
        if started:
            if source == "pool":
                self._rot[cue.name] = self._rot.get(cue.name, 0) + 1
            if self._log is not None:
                self._log(f"chatter[{source}] {cue.name} -> {cue.bus}: {text}")
        return started


# ---- the shipped chatter categories ---------------------------------------------------------
# Eligibility is a function of state: station traffic only where there are stations (populated);
# deep-space musings only out in the black. All ride the Comms bus (radio-flavored) and are
# throttled by their own cooldown plus the global C3 governor.
def chatter_cues() -> list[Cue]:
    return [
        Cue(
            "station_traffic", COMMS, {POPULATED}, cooldown_s=90.0, fact_bearing=True,
            phrasings=(
                "Traffic's steady around here.",
                "Plenty of ships on the scope today.",
                "Docking lanes are busy.",
            ),
        ),
        Cue(
            "supercruise_ambient", COMMS, {SUPERCRUISE}, cooldown_s=100.0, fact_bearing=True,
            phrasings=(
                "Cruise is holding smooth.",
                "Frame shift steady.",
            ),
        ),
        Cue(
            "deep_space_musing", COMMS, {DEEP_SPACE, UNPOPULATED}, cooldown_s=150.0,
            fact_bearing=False,   # pure atmosphere -> LLM permitted (validated), pool fallback
            phrasings=(
                "Quiet out here. Just us and the dark.",
                "Long way from anywhere.",
                "Nothing but starlight for company.",
            ),
        ),
        Cue(
            "open_space_idle", COMMS, {NORMAL_SPACE}, cooldown_s=120.0, fact_bearing=False,
            phrasings=(
                "All quiet on the scope.",
                "Smooth flying.",
            ),
        ),
    ]


def register_chatter(registry) -> None:  # noqa: ANN001 — a CueRegistry
    """Register every shipped chatter cue with the cue registry."""
    for cue in chatter_cues():
        registry.register(cue)
